if(fpcm===void 0)var fpcm={};fpcm.editor={init:function(){if(!fpcm.editor.initToolbar)return fpcm.ui.addMessage({txt:"Failed to init editor toolbar, fpcm.editor.initToolbar not defined",type:"error"}),!1;if(!fpcm.editor.initEditor)return fpcm.ui.addMessage({txt:"Failed to init editor toolbar, fpcm.editor.initEditor not defined",type:"error"}),!1;fpcm.editor.initToolbar(),fpcm.editor.initEditor({elementId:fpcm.ui.prepareId("content-ace",!0),textareaId:"commenttext",type:"commenttext"})},initAfter:function(){fpcm.ui.autocomplete("#commentarticle",{source:fpcm.vars.ajaxActionPath+"autocomplete&src=articles",minLength:3}),fpcm.dom.bindClick("#btnLockIp",function(e){var n=fpcm.dom.fromTag(e.currentTarget).data("commentid");return fpcm.ui_dialogs.confirm({clickYes:function(){fpcm.ajax.post("comments/lockip",{dataType:"json",data:{cid:n},execDone:function(e){fpcm.ui.addMessage(e)}})}}),!1})},initTinyMce:function(){fpcm.editor_tinymce.create(fpcm.vars.jsvars.editorConfig)},initAce:function(){fpcm.editor_ace.create({elementId:fpcm.ui.prepareId("content-ace",!0),textareaId:"commenttext",type:"commenttext"})},getGalleryReplacement:function(e){return fpcm.vars.jsvars.editorGalleryTagStart.replace("{{IMAGES}}",fpcm.vars.jsvars.editorGalleryTagThumb+e.join(fpcm.vars.jsvars.editorGalleryTagLink+"|"+fpcm.vars.jsvars.editorGalleryTagThumb)+fpcm.vars.jsvars.editorGalleryTagLink)}}